func disconnect() {
    serverConfigStore.removeAllServers()
    dependencies?.refreshServices()
    backendConfig = nil
    currentUser = nil
    phase = .serverConnection
    // ChatFort override: keep the default server URL so auto-connect works.
    serverURL = "https://chat.chatfort.ai"
    apiKey = ""
    stopTokenRefreshTimer()
    // ChatFort override: clear Authentik session cookies so the proxy
    // requires re-authentication on next connect.
    if let cookies = HTTPCookieStorage.shared.cookies {
        for cookie in cookies {
            HTTPCookieStorage.shared.deleteCookie(cookie)
        }
    }
}

